package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // We override readLine to call super.readLine() from BufferedReader
            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        };
    }

    @Test
    void testReadLine_withNonEmptyLine() throws Exception {
        ExtendedBufferedReader spyReader = spy(new ExtendedBufferedReader(mockReader));

        // Mock the super.readLine() call inside ExtendedBufferedReader.readLine()
        // To do this properly, we need to mock the internal reader to return the line
        doReturn("Hello World").when(spyReader).readLine();

        // But this will cause infinite recursion, so instead we mock the underlying reader
        Reader mockInternalReader = mock(Reader.class);
        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockInternalReader) {
            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        };

        ExtendedBufferedReader spy = spy(reader);

        // We mock the super.readLine() by mocking the underlying BufferedReader's readLine method.
        // Since BufferedReader.readLine() is final, we cannot mock it directly.
        // So we mock the underlying reader to return characters that form "Hello World\n"

        // Instead, we can use a real StringReader to avoid mocking complexity
        java.io.StringReader stringReader = new java.io.StringReader("Hello World\n");
        ExtendedBufferedReader realReader = new ExtendedBufferedReader(stringReader);

        String result = realReader.readLine();

        assertEquals("Hello World", result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(realReader);
        assertEquals('d', lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(realReader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_withEmptyLine() throws Exception {
        java.io.StringReader stringReader = new java.io.StringReader("\n");
        ExtendedBufferedReader realReader = new ExtendedBufferedReader(stringReader);

        String result = realReader.readLine();

        assertEquals("", result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(realReader);
        // lastChar should remain UNDEFINED because line length is 0
        assertEquals(ExtendedBufferedReader.UNDEFINED, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(realReader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_withNullLine() throws Exception {
        java.io.StringReader stringReader = new java.io.StringReader("");
        ExtendedBufferedReader realReader = new ExtendedBufferedReader(stringReader);

        // Read all lines until null is returned
        String line = realReader.readLine(); // first call returns null because input is empty

        assertNull(line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = lastCharField.getInt(realReader);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = lineCounterField.getInt(realReader);
        // lineCounter should remain 0 because line was null
        assertEquals(0, lineCounter);
    }
}
